# tuple is an ordered datatype which is used to store multiple values in a single variable and it can store duplicate vaules
# and tuple datatype is immutable which means if once created then you cannot modify it 

# let's see how we can write tuple and we will see it's syntax
syntax_1_tuple = (1 , 2 , 3)                  # it's a tuple literal
syntax_2_tuple = 1 , 2 , 3                    # it's also a tuple, now you will get confusion how it can be tuple, understand one thing, parentheses dosen't define the tuple but the comma(,) defines the tuple, this is called implicit tuple no parentheses needed
syntax_3_tuple = (10)                         # this is not a tuple , because one value without comma wouldn't be a tuple 
syntax_4_tuple = (10,)                        # this is a tuple , because even through it contains one value but after the value the comma is seperating
syntax_5_tuple = 22,                          # this is a tuple
syntax_6_tuple = tuple("hello")               # tuple from a string --> `('h' , 'e' , 'l' , 'l' , 'o')`
syntax_7_tuple = tuple([1 , "hell" , True])   # tuple from a list
# you can see every output below with it's datatype
print(f"{syntax_1_tuple} {type(syntax_1_tuple)}\n{syntax_2_tuple} {type(syntax_2_tuple)}\n{syntax_3_tuple} {type(syntax_3_tuple)}\n{syntax_4_tuple} {type(syntax_4_tuple)}\n{syntax_5_tuple} {type(syntax_5_tuple)}\n{syntax_6_tuple} {type(syntax_6_tuple)}\n{syntax_7_tuple} {type(syntax_7_tuple)}")
print("\n")

# there are two ways to create a empty tuple
empty_tuple_1 = ()
print(empty_tuple_1 , type(empty_tuple_1))
empty_tuple_2 = tuple()
print(empty_tuple_2 , type(empty_tuple_2))
print("\n")


