# Indexing in tuple
indexing_tuple = (1 , 2 , 3 , 4 , 5 , 6 , 7 , 8 , 9)
print(indexing_tuple[3])
print(indexing_tuple[-3])

# Slicing in tuple
slicing_tuple = (1 , 2 , 3 , 4 , 5 , 6 , 7 , 8 , 9)
print(slicing_tuple[0:8:])

# In Slicing and Indexing original stays unchanged, only the print displays new tuple

# nested tuple
nested_tuple = ((1 , 2) , (3 , 4) , (5 , 6))
print(nested_tuple[1][0])
print("\n")


