# Now we will see an importand topic which is packing and unpacking 

# Packing
# packing means putting multiple values into a single tuple automatically
packing_tuple = 1 , 2 , 3 , 4 , 5
print(packing_tuple , type(packing_tuple) , sep="\n")



# Unpacking 
# tuple unpacking allow you to assign tuple elements to individual variables in a single operations
unpacking_tuple = (1 , 2 , 3)
a , b , c = unpacking_tuple
print(a)
print(b)
print(c)
# here you can see that every tuple values in stored inside a separate variable
print("\n")
# a , b = unpacking_tuple ❌ it will raise ValueError: too many values to unpack , so now we will see extended unpacking

# extended unpacking (*)
d , *e = unpacking_tuple
print(d)
print(e)
# here we can see, when we use * before any variable name then it puts all the remaining vaues inside a list and store it in the variable
# But you can get doubt when we are using an extended unpacking in tuple then why it store in list why not in tuple , because python need a flexible container where list is mutable and tuple is immutable , that's why list is used
print("\n")

# nested unpacking
nested_unpacking = (1 , 2 , (3 , 4) , 5)
a, b, (c, d), e = nested_unpacking # if you want to unpack the nested tuple then put the variable inside the parentheses
print(c)
print("\n")


